'use strict';

const fs = require('node:fs');
const path = require('node:path');
const yaml = require('js-yaml');

class ParseError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ParseError';
  }
}

/**
 * Find SKILL.md in a directory (case-insensitive, prefers SKILL.md).
 * @param {string} skillDir - Path to skill directory
 * @returns {string|null} Path to SKILL.md or null
 */
function findSkillMd(skillDir) {
  let entries;
  try {
    entries = fs.readdirSync(skillDir);
  } catch {
    return null;
  }

  // Prefer SKILL.md, fall back to skill.md
  const preferred = entries.find((e) => e === 'SKILL.md');
  if (preferred) return path.join(skillDir, preferred);

  const fallback = entries.find((e) => e.toLowerCase() === 'skill.md');
  if (fallback) return path.join(skillDir, fallback);

  return null;
}

/**
 * Parse YAML frontmatter from SKILL.md content.
 * @param {string} content - Raw file content
 * @returns {{ metadata: object, body: string }}
 * @throws {ParseError}
 */
function parseFrontmatter(content) {
  if (!content.startsWith('---')) {
    throw new ParseError('SKILL.md must start with YAML frontmatter (---)');
  }

  // Split on --- (max 3 parts: empty before first ---, frontmatter, body)
  const marker = '---';
  const firstEnd = content.indexOf(marker, 3);
  if (firstEnd === -1) {
    throw new ParseError('SKILL.md frontmatter not properly closed with ---');
  }

  const rawYaml = content.slice(3, firstEnd);
  const body = content.slice(firstEnd + 3);

  let metadata;
  try {
    metadata = yaml.load(rawYaml);
  } catch (error) {
    throw new ParseError(`Invalid YAML in frontmatter: ${error.message}`);
  }

  if (metadata === null || metadata === undefined || typeof metadata !== 'object' || Array.isArray(metadata)) {
    throw new ParseError('SKILL.md frontmatter must be a YAML mapping');
  }

  // Normalize metadata field: convert all keys/values to strings
  if (metadata.metadata && typeof metadata.metadata === 'object') {
    const normalized = {};
    for (const [key, value] of Object.entries(metadata.metadata)) {
      normalized[String(key)] = String(value);
    }
    metadata.metadata = normalized;
  }

  return { metadata, body };
}

/**
 * Resolve a skill path — if it's a SKILL.md file, return the parent directory.
 * @param {string} inputPath
 * @returns {string}
 */
function resolveSkillPath(inputPath) {
  const resolved = path.resolve(inputPath);
  const basename = path.basename(resolved);
  if (basename.toLowerCase() === 'skill.md') {
    return path.dirname(resolved);
  }
  return resolved;
}

module.exports = { ParseError, findSkillMd, parseFrontmatter, resolveSkillPath };

