'use strict';

const fs = require('node:fs');
const { ParseError, findSkillMd, parseFrontmatter } = require('./parser');

/**
 * Skill properties extracted from SKILL.md frontmatter.
 */
class SkillProperties {
  constructor({ name, description, license, compatibility, allowedTools, metadata }) {
    this.name = name;
    this.description = description;
    this.license = license || null;
    this.compatibility = compatibility || null;
    this.allowedTools = allowedTools || null;
    this.metadata = metadata || {};
  }

  toDict() {
    const result = {
      name: this.name,
      description: this.description,
    };
    if (this.license !== null) result.license = this.license;
    if (this.compatibility !== null) result.compatibility = this.compatibility;
    if (this.allowedTools !== null) result['allowed-tools'] = this.allowedTools;
    if (Object.keys(this.metadata).length > 0) result.metadata = this.metadata;
    return result;
  }
}

/**
 * Read and parse skill properties from a skill directory.
 * @param {string} skillDir - Path to skill directory
 * @returns {SkillProperties}
 * @throws {ParseError}
 */
function readProperties(skillDir) {
  const skillMdPath = findSkillMd(skillDir);
  if (!skillMdPath) {
    throw new ParseError(`SKILL.md not found in ${skillDir}`);
  }

  const content = fs.readFileSync(skillMdPath, 'utf-8');
  const { metadata } = parseFrontmatter(content);

  if (!metadata.name) {
    throw new ParseError('Missing required field in frontmatter: name');
  }
  if (!metadata.description) {
    throw new ParseError('Missing required field in frontmatter: description');
  }

