#!/usr/bin/env node
'use strict';

const { Command } = require('commander');
const { resolve } = require('node:path');
const { resolveSkillPath } = require('./lib/parser');
const { validate } = require('./lib/validator');
const { readProperties } = require('./lib/properties');
const { toPrompt } = require('./lib/prompt');

const program = new Command();

program
  .name('skill-check')
  .description('Validate agent skills against the agentskills.io specification')
  .version('1.0.0');

program
  .command('validate')
  .description('Validate a skill directory')
  .argument('<path>', 'Path to skill directory or SKILL.md file')
  .action((inputPath) => {
    const skillDir = resolveSkillPath(inputPath);
    const errors = validate(skillDir);

    if (errors.length > 0) {
      for (const error of errors) {
        process.stderr.write(`  - ${error}\n`);
      }
      process.exit(1);
    }

    console.log(`Valid skill: ${resolve(skillDir)}`);
  });

program
  .command('read-properties')
  .description('Read skill frontmatter as JSON')
  .argument('<path>', 'Path to skill directory or SKILL.md file')
  .action((inputPath) => {
    const skillDir = resolveSkillPath(inputPath);
    try {
      const props = readProperties(skillDir);
      console.log(JSON.stringify(props.toDict(), null, 2));
    } catch (error) {
      process.stderr.write(`${error.message}\n`);
      process.exit(1);
    }
  });

program
  .command('to-prompt')
  .description('Generate <available_skills> XML block for agent system prompts')
  .argument('<paths...>', 'One or more paths to skill directories or SKILL.md files')
  .action((paths) => {
    try {
      const resolved = paths.map((p) => resolveSkillPath(p));
      const output = toPrompt(resolved);
      console.log(output);
    } catch (error) {
      process.stderr.write(`${error.message}\n`);
      process.exit(1);
    }
  });

program.parse();

