'use strict';

const fs = require('node:fs');
const path = require('node:path');
const os = require('node:os');
const { execSync } = require('node:child_process');

const { validate, validateMetadata, ALLOWED_FIELDS } = require('../tools/skill-check/lib/validator');
const { parseFrontmatter, findSkillMd, ParseError } = require('../tools/skill-check/lib/parser');
const { SkillProperties, readProperties } = require('../tools/skill-check/lib/properties');
const { toPrompt, escapeXml } = require('../tools/skill-check/lib/prompt');

// ── Test helpers ──

const RESET = '\x1b[0m';
const GREEN = '\x1b[32m';
const RED = '\x1b[31m';
const CYAN = '\x1b[36m';
const YELLOW = '\x1b[33m';

let passed = 0;
let failed = 0;

function assert(condition, message) {
  if (condition) {
    console.log(`${GREEN}✓${RESET} ${message}`);
    passed++;
  } else {
    console.log(`${RED}✗${RESET} ${message}`);
    failed++;
  }
}

function assertDeepEqual(actual, expected, message) {
  const match = JSON.stringify(actual) === JSON.stringify(expected);
  if (!match) {
    console.log(`${RED}✗${RESET} ${message}`);
    console.log(`  Expected: ${JSON.stringify(expected)}`);
    console.log(`  Actual:   ${JSON.stringify(actual)}`);
    failed++;
  } else {
    console.log(`${GREEN}✓${RESET} ${message}`);
    passed++;
  }
}

function suite(name) {
  console.log(`\n${YELLOW}${name}${RESET}\n`);
}

/**
 * Create a temporary skill directory with SKILL.md content.
 * @param {string} dirName - Directory name
 * @param {string} content - SKILL.md content
 * @returns {string} Path to created directory
 */
function createSkill(dirName, content) {
  const dir = path.join(tmpDir, dirName);
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, 'SKILL.md'), content, 'utf-8');
  return dir;
}

// ── Setup ──

const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'skill-check-test-'));

console.log(`${CYAN}========================================`);
console.log(`Skill Check Test Suite`);
console.log(`========================================${RESET}`);

// ── Parser Tests ──

suite('Test Suite 1: Frontmatter Parsing');

{
  const { metadata, body } = parseFrontmatter('---\nname: test\ndescription: A test skill\n---\n# Body');
  assert(metadata.name === 'test', 'parses name from frontmatter');
  assert(metadata.description === 'A test skill', 'parses description from frontmatter');
  assert(body.trim() === '# Body', 'extracts body after frontmatter');
}

{
  let threw = false;
  try {
    parseFrontmatter('# No frontmatter');
  } catch (error) {
    threw = error instanceof ParseError && error.message.includes('must start with YAML frontmatter');
  }
  assert(threw, 'rejects content without frontmatter');
}

{
  let threw = false;
  try {
    parseFrontmatter('---\nname: test\n# Never closed');
  } catch (error) {
    threw = error instanceof ParseError && error.message.includes('not properly closed');
  }
  assert(threw, 'rejects unclosed frontmatter');
}

{
  let threw = false;
  try {
    parseFrontmatter('---\n: invalid: yaml:\n---\n');
  } catch (error) {
    threw = error instanceof ParseError && error.message.includes('Invalid YAML');
  }
  assert(threw, 'rejects invalid YAML');
}

{
  let threw = false;
  try {
    parseFrontmatter('---\n- a list\n- not a mapping\n---\n');
  } catch (error) {
    threw = error instanceof ParseError && error.message.includes('must be a YAML mapping');
  }
  assert(threw, 'rejects non-mapping frontmatter');
}

{
  const { metadata } = parseFrontmatter(
    '---\nname: test\ndescription: d\nmetadata:\n  version: "1.0"\n  author: someone\n---\n',
  );
  assert(typeof metadata.metadata === 'object', 'parses metadata field as object');
  assert(metadata.metadata.version === '1.0', 'metadata values are strings');
  assert(metadata.metadata.author === 'someone', 'metadata preserves keys');
}

// ── findSkillMd Tests ──

suite('Test Suite 2: SKILL.md Discovery');

{
  const dir = createSkill('find-test', '---\nname: find-test\ndescription: d\n---\n');
  const found = findSkillMd(dir);
  assert(found !== null, 'finds SKILL.md in directory');
  assert(path.basename(found) === 'SKILL.md', 'returns correct filename');
}

{
  const dir = path.join(tmpDir, 'empty-dir');
  fs.mkdirSync(dir, { recursive: true });
  const found = findSkillMd(dir);
  assert(found === null, 'returns null for directory without SKILL.md');
}

{
  // Test case-insensitive fallback
  const dir = path.join(tmpDir, 'lowercase-test');
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, 'skill.md'), '---\nname: test\ndescription: d\n---\n');
  const found = findSkillMd(dir);
  assert(found !== null, 'finds lowercase skill.md');
}

// ── Validator Tests ──

suite('Test Suite 3: Validation — Valid Skills');

{
  const dir = createSkill('valid-minimal', '---\nname: valid-minimal\ndescription: A valid skill.\n---\n# Skill');
  const errors = validate(dir);
  assert(errors.length === 0, 'minimal valid skill passes');
}

{
  const content = [
    '---',
    'name: full-skill',
    'description: A fully specified skill.',
    'license: MIT',
    'compatibility: Requires node >= 22',
    'allowed-tools: Bash Read',
    'metadata:',
    '  author: test',
    '  version: "1.0"',
    '---',
    '# Full Skill',
  ].join('\n');
  const dir = createSkill('full-skill', content);
  const errors = validate(dir);
  assert(errors.length === 0, 'skill with all optional fields passes');
}

suite('Test Suite 4: Validation — Path Errors');

{
  const errors = validate('/nonexistent/path/to/skill');
  assert(errors.length === 1 && errors[0].includes('does not exist'), 'rejects nonexistent path');
}

{
  const filePath = path.join(tmpDir, 'not-a-dir.txt');
