'use strict';

const path = require('node:path');
const { readProperties } = require('./properties');
const { findSkillMd } = require('./parser');

/**
 * Escape XML special characters.
 * @param {string} text
 * @returns {string}
 */
function escapeXml(text) {
  return text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

/**
 * Generate an <available_skills> XML block for agent system prompts.
 * @param {string[]} skillDirs - Paths to skill directories
 * @returns {string}
 */
function toPrompt(skillDirs) {
  const lines = ['<available_skills>'];

  for (const dir of skillDirs) {
    const resolved = path.resolve(dir);
    const props = readProperties(resolved);
    const skillMdPath = findSkillMd(resolved);

    lines.push('<skill>');
    lines.push(`<name>${escapeXml(props.name)}</name>`);
    lines.push(`<description>${escapeXml(props.description)}</description>`);
    lines.push(`<location>${skillMdPath}</location>`);
    lines.push('</skill>');
  }

  lines.push('</available_skills>');
  return lines.join('\n');
}

module.exports = { toPrompt, escapeXml };

