'use strict';

const fs = require('node:fs');
const path = require('node:path');
const { ParseError, findSkillMd, parseFrontmatter } = require('./parser');

const MAX_SKILL_NAME_LENGTH = 64;
const MAX_DESCRIPTION_LENGTH = 1024;
const MAX_COMPATIBILITY_LENGTH = 500;

const ALLOWED_FIELDS = new Set(['name', 'description', 'license', 'allowed-tools', 'metadata', 'compatibility']);

/**
 * Validate a skill directory against the agentskills.io specification.
 * @param {string} skillDir - Path to skill directory
 * @returns {string[]} List of error messages (empty = valid)
 */
function validate(skillDir) {
  if (!fs.existsSync(skillDir)) {
    return [`Path does not exist: ${skillDir}`];
  }

  const stat = fs.statSync(skillDir);
  if (!stat.isDirectory()) {
    return [`Not a directory: ${skillDir}`];
  }

  const skillMdPath = findSkillMd(skillDir);
  if (!skillMdPath) {
    return ['Missing required file: SKILL.md'];
  }

  const content = fs.readFileSync(skillMdPath, 'utf-8');

  let metadata;
  try {
    ({ metadata } = parseFrontmatter(content));
  } catch (error) {
    if (error instanceof ParseError) {
      return [error.message];
    }
    throw error;
  }

  return validateMetadata(metadata, skillDir);
}

/**
 * Validate frontmatter metadata against the agentskills.io specification.
 * @param {object} metadata - Parsed frontmatter
 * @param {string|null} skillDir - Skill directory path (for name matching)
 * @returns {string[]} List of error messages
 */
function validateMetadata(metadata, skillDir) {
  const errors = [];

  errors.push(...validateMetadataFields(metadata));
  errors.push(...validateName(metadata, skillDir));
  errors.push(...validateDescription(metadata));
  errors.push(...validateCompatibility(metadata));

  return errors;
}

/**
 * Check for unknown frontmatter fields.
 */
function validateMetadataFields(metadata) {
  const unknown = Object.keys(metadata).filter((key) => !ALLOWED_FIELDS.has(key));
  if (unknown.length > 0) {
    const allowed = [...ALLOWED_FIELDS].sort().join(', ');
    return [`Unexpected fields in frontmatter: ${unknown.join(', ')}. Only ${allowed} are allowed.`];
  }
  return [];
}

/**
 * Validate the name field.
 */
function validateName(metadata, skillDir) {
  const errors = [];

  if (metadata.name === undefined || metadata.name === null) {
    return ['Missing required field in frontmatter: name'];
  }

  if (typeof metadata.name !== 'string' || metadata.name.trim() === '') {
    return ["Field 'name' must be a non-empty string"];
  }

  const name = metadata.name.normalize('NFKC');

  if (name.length > MAX_SKILL_NAME_LENGTH) {
    errors.push(`Skill name '${name}' exceeds 64 character limit (${name.length} chars)`);
  }

  if (name !== name.toLowerCase()) {
    errors.push(`Skill name '${name}' must be lowercase`);
  }

  if (name.startsWith('-') || name.endsWith('-')) {
    errors.push('Skill name cannot start or end with a hyphen');
  }

  if (name.includes('--')) {
    errors.push('Skill name cannot contain consecutive hyphens');
  }

  // Only alphanumeric + hyphens allowed
  if (!/^[\da-z-]+$/.test(name)) {
    errors.push(
      `Skill name '${name}' contains invalid characters. Only letters, digits, and hyphens are allowed.`,
    );
  }

  // Name must match directory name
  if (skillDir) {
    const dirName = path.basename(skillDir).normalize('NFKC');
    if (dirName !== name) {
      errors.push(`Directory name '${dirName}' must match skill name '${name}'`);
    }
  }

  return errors;
}

/**
 * Validate the description field.
 */
function validateDescription(metadata) {
  if (metadata.description === undefined || metadata.description === null) {
    return ['Missing required field in frontmatter: description'];
  }

  if (typeof metadata.description !== 'string' || metadata.description.trim() === '') {
    return ["Field 'description' must be a non-empty string"];
  }

  if (metadata.description.length > MAX_DESCRIPTION_LENGTH) {
    return [`Description exceeds 1024 character limit (${metadata.description.length} chars)`];
  }

  return [];
}

/**
 * Validate the optional compatibility field.
 */
function validateCompatibility(metadata) {
  if (metadata.compatibility === undefined || metadata.compatibility === null) {
    return [];
  }

  if (typeof metadata.compatibility !== 'string') {
    return ["Field 'compatibility' must be a string"];
  }

  if (metadata.compatibility.length > MAX_COMPATIBILITY_LENGTH) {
    return [`Compatibility exceeds 500 character limit (${metadata.compatibility.length} chars)`];
  }

  return [];
}

module.exports = {
  validate,
  validateMetadata,
  MAX_SKILL_NAME_LENGTH,
  MAX_DESCRIPTION_LENGTH,
  MAX_COMPATIBILITY_LENGTH,
  ALLOWED_FIELDS,
};

