'use strict';

const fs = require('node:fs');
const path = require('node:path');
const os = require('node:os');
const { execSync } = require('node:child_process');

const { validate, validateMetadata, ALLOWED_FIELDS } = require('../tools/skill-check/lib/validator');
const { parseFrontmatter, findSkillMd, ParseError } = require('../tools/skill-check/lib/parser');
const { SkillProperties, readProperties } = require('../tools/skill-check/lib/properties');
const { toPrompt, escapeXml } = require('../tools/skill-check/lib/prompt');

// ── Test helpers ──

const RESET = '\x1b[0m';
const GREEN = '\x1b[32m';
const RED = '\x1b[31m';
const CYAN = '\x1b[36m';
const YELLOW = '\x1b[33m';

let passed = 0;
let failed = 0;

function assert(condition, message) {
  if (condition) {
    console.log(`${GREEN}✓${RESET} ${message}`);
    passed++;
  } else {
    console.log(`${RED}✗${RESET} ${message}`);
    failed++;
  }
}

function assertDeepEqual(actual, expected, message) {
  const match = JSON.stringify(actual) === JSON.stringify(expected);
  if (!match) {
    console.log(`${RED}✗${RESET} ${message}`);
    console.log(`  Expected: ${JSON.stringify(expected)}`);
    console.log(`  Actual:   ${JSON.stringify(actual)}`);
    failed++;
  } else {
    console.log(`${GREEN}✓${RESET} ${message}`);
    passed++;
  }
}

function suite(name) {
  console.log(`\n${YELLOW}${name}${RESET}\n`);
}

/**
 * Create a temporary skill directory with SKILL.md content.
 * @param {string} dirName - Directory name
 * @param {string} content - SKILL.md content
 * @returns {string} Path to created directory
 */
function createSkill(dirName, content) {
  const dir = path.join(tmpDir, dirName);
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, 'SKILL.md'), content, 'utf-8');
  return dir;
}

// ── Setup ──

const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'skill-check-test-'));

console.log(`${CYAN}========================================`);
console.log(`Skill Check Test Suite`);
console.log(`========================================${RESET}`);

// ── Parser Tests ──

suite('Test Suite 1: Frontmatter Parsing');

{
  const { metadata, body } = parseFrontmatter('---\nname: test\ndescription: A test skill\n---\n# Body');
  assert(metadata.name === 'test', 'parses name from frontmatter');
  assert(metadata.description === 'A test skill', 'parses description from frontmatter');
  assert(body.trim() === '# Body', 'extracts body after frontmatter');
}

{
  let threw = false;
  try {
    parseFrontmatter('# No frontmatter');
  } catch (error) {
    threw = error instanceof ParseError && error.message.includes('must start with YAML frontmatter');
  }
  assert(threw, 'rejects content without frontmatter');
}

{
  let threw = false;
  try {
    parseFrontmatter('---\nname: test\n# Never closed');
  } catch (error) {
    threw = error instanceof ParseError && error.message.includes('not properly closed');
  }
  assert(threw, 'rejects unclosed frontmatter');
}

{
  let threw = false;
  try {
    parseFrontmatter('---\n: invalid: yaml:\n---\n');
  } catch (error) {
    threw = error instanceof ParseError && error.message.includes('Invalid YAML');
  }
  assert(threw, 'rejects invalid YAML');
}

{
  let threw = false;
  try {
    parseFrontmatter('---\n- a list\n- not a mapping\n---\n');
  } catch (error) {
    threw = error instanceof ParseError && error.message.includes('must be a YAML mapping');
  }
  assert(threw, 'rejects non-mapping frontmatter');
}

{
  const { metadata } = parseFrontmatter(
    '---\nname: test\ndescription: d\nmetadata:\n  version: "1.0"\n  author: someone\n---\n',
  );
  assert(typeof metadata.metadata === 'object', 'parses metadata field as object');
  assert(metadata.metadata.version === '1.0', 'metadata values are strings');
  assert(metadata.metadata.author === 'someone', 'metadata preserves keys');
}

// ── findSkillMd Tests ──

suite('Test Suite 2: SKILL.md Discovery');

{
  const dir = createSkill('find-test', '---\nname: find-test\ndescription: d\n---\n');
  const found = findSkillMd(dir);
  assert(found !== null, 'finds SKILL.md in directory');
  assert(path.basename(found) === 'SKILL.md', 'returns correct filename');
}

{
  const dir = path.join(tmpDir, 'empty-dir');
  fs.mkdirSync(dir, { recursive: true });
  const found = findSkillMd(dir);
  assert(found === null, 'returns null for directory without SKILL.md');
}

{
  // Test case-insensitive fallback
  const dir = path.join(tmpDir, 'lowercase-test');
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, 'skill.md'), '---\nname: test\ndescription: d\n---\n');
  const found = findSkillMd(dir);
  assert(found !== null, 'finds lowercase skill.md');
}

// ── Validator Tests ──

suite('Test Suite 3: Validation — Valid Skills');

{
  const dir = createSkill('valid-minimal', '---\nname: valid-minimal\ndescription: A valid skill.\n---\n# Skill');
  const errors = validate(dir);
  assert(errors.length === 0, 'minimal valid skill passes');
}

{
  const content = [
    '---',
    'name: full-skill',
    'description: A fully specified skill.',
    'license: MIT',
    'compatibility: Requires node >= 22',
    'allowed-tools: Bash Read',
    'metadata:',
    '  author: test',
    '  version: "1.0"',
    '---',
    '# Full Skill',
  ].join('\n');
  const dir = createSkill('full-skill', content);
  const errors = validate(dir);
  assert(errors.length === 0, 'skill with all optional fields passes');
}

suite('Test Suite 4: Validation — Path Errors');

{
  const errors = validate('/nonexistent/path/to/skill');
  assert(errors.length === 1 && errors[0].includes('does not exist'), 'rejects nonexistent path');
}

{
  const filePath = path.join(tmpDir, 'not-a-dir.txt');
  fs.writeFileSync(filePath, 'not a directory');
  const errors = validate(filePath);
  assert(errors.length === 1 && errors[0].includes('Not a directory'), 'rejects non-directory path');
}

{
  const dir = path.join(tmpDir, 'no-skill-md');
  fs.mkdirSync(dir, { recursive: true });
  const errors = validate(dir);
  assert(errors.length === 1 && errors[0].includes('Missing required file'), 'rejects directory without SKILL.md');
}

suite('Test Suite 5: Validation — Name Errors');

{
  const dir = createSkill('uppercase-name', '---\nname: UpperCase\ndescription: d\n---\n');
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('must be lowercase')), 'rejects uppercase name');
}

{
  const longName = 'a'.repeat(65);
  const dir = createSkill(longName, `---\nname: ${longName}\ndescription: d\n---\n`);
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('exceeds 64 character limit')), 'rejects name over 64 chars');
}

{
  const dir = createSkill('-leading-hyphen', '---\nname: -leading-hyphen\ndescription: d\n---\n');
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('cannot start or end with a hyphen')), 'rejects leading hyphen');
}

{
  const dir = createSkill('trailing-hyphen-', '---\nname: trailing-hyphen-\ndescription: d\n---\n');
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('cannot start or end with a hyphen')), 'rejects trailing hyphen');
}

{
  const dir = createSkill('double--hyphen', '---\nname: double--hyphen\ndescription: d\n---\n');
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('consecutive hyphens')), 'rejects consecutive hyphens');
}

{
  const dir = createSkill('invalid_chars', '---\nname: invalid_chars\ndescription: d\n---\n');
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('invalid characters')), 'rejects underscores in name');
}

{
  const dir = createSkill('dir-mismatch', '---\nname: other-name\ndescription: d\n---\n');
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('must match skill name')), 'rejects name/directory mismatch');
}

{
  const dir = createSkill('no-name', '---\ndescription: d\n---\n');
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('Missing required field in frontmatter: name')), 'rejects missing name');
}

suite('Test Suite 6: Validation — Description Errors');

{
  const dir = createSkill('no-desc', '---\nname: no-desc\n---\n');
  const errors = validate(dir);
  assert(
    errors.some((e) => e.includes('Missing required field in frontmatter: description')),
    'rejects missing description',
  );
}

{
  const longDesc = 'x'.repeat(1025);
  const dir = createSkill('long-desc', `---\nname: long-desc\ndescription: "${longDesc}"\n---\n`);
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('exceeds 1024 character limit')), 'rejects description over 1024 chars');
}

suite('Test Suite 7: Validation — Compatibility Errors');

{
  const longCompat = 'y'.repeat(501);
  const content = `---\nname: compat-test\ndescription: d\ncompatibility: "${longCompat}"\n---\n`;
  const dir = createSkill('compat-test', content);
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('Compatibility exceeds 500')), 'rejects compatibility over 500 chars');
}

suite('Test Suite 8: Validation — Unknown Fields');

{
  const content = '---\nname: unknown-field\ndescription: d\nversion: "1.0"\nauthor: test\n---\n';
  const dir = createSkill('unknown-field', content);
  const errors = validate(dir);
  assert(errors.some((e) => e.includes('Unexpected fields')), 'rejects unknown frontmatter fields');
  assert(errors.some((e) => e.includes('version') && e.includes('author')), 'lists specific unknown fields');
}

// ── Properties Tests ──

suite('Test Suite 9: Read Properties');

{
  const dir = createSkill('props-test', '---\nname: props-test\ndescription: A test skill.\n---\n');
  const props = readProperties(dir);
  assert(props.name === 'props-test', 'reads name property');
  assert(props.description === 'A test skill.', 'reads description property');
  assert(props.license === null, 'missing optional fields are null');

  const dict = props.toDict();
  assert(dict.name === 'props-test', 'toDict includes name');
  assert(dict.description === 'A test skill.', 'toDict includes description');
  assert(dict.license === undefined, 'toDict excludes null fields');
}

{
  const content =
    '---\nname: full-props\ndescription: d\nlicense: MIT\nallowed-tools: Bash Read\nmetadata:\n  k: v\n---\n';
  const dir = createSkill('full-props', content);
  const props = readProperties(dir);
  assert(props.license === 'MIT', 'reads optional license');
  assert(props.allowedTools === 'Bash Read', 'reads allowed-tools');
  assert(props.metadata.k === 'v', 'reads metadata');

  const dict = props.toDict();
  assert(dict['allowed-tools'] === 'Bash Read', 'toDict maps allowedTools to allowed-tools');
  assert(dict.metadata.k === 'v', 'toDict includes metadata');
}

// ── Prompt Tests ──

suite('Test Suite 10: Prompt Generation');

{
  assert(escapeXml('<tag>') === '&lt;tag&gt;', 'escapes angle brackets');
  assert(escapeXml('a & b') === 'a &amp; b', 'escapes ampersands');
  assert(escapeXml('plain') === 'plain', 'leaves plain text unchanged');
}

{
  const dir = createSkill('prompt-skill', '---\nname: prompt-skill\ndescription: A prompt test.\n---\n');
  const output = toPrompt([dir]);
  assert(output.includes('<available_skills>'), 'output contains opening tag');
  assert(output.includes('</available_skills>'), 'output contains closing tag');
  assert(output.includes('<name>prompt-skill</name>'), 'output contains skill name');
  assert(output.includes('<description>A prompt test.</description>'), 'output contains skill description');
  assert(output.includes('<location>'), 'output contains location tag');
}

{
  const output = toPrompt([]);
  assert(output === '<available_skills>\n</available_skills>', 'empty list produces empty block');
}

{
  const dir = createSkill('xml-escape', '---\nname: xml-escape\ndescription: "Use <b> & tags"\n---\n');
  const output = toPrompt([dir]);
  assert(output.includes('&lt;b&gt; &amp; tags'), 'escapes XML special characters in description');
}

// ── CLI Integration Tests ──

suite('Test Suite 11: CLI Integration');

{
  const dir = createSkill('cli-valid', '---\nname: cli-valid\ndescription: CLI test skill.\n---\n');
  const cliPath = path.resolve(__dirname, '..', 'tools', 'skill-check', 'skill-check.js');
  const result = execSync(`node "${cliPath}" validate "${dir}"`, { encoding: 'utf-8' });
  assert(result.includes('Valid skill'), 'CLI validate reports valid skill');
}

{
  const dir = createSkill('cli-invalid', '---\nname: WRONG\ndescription: d\n---\n');
  const cliPath = path.resolve(__dirname, '..', 'tools', 'skill-check', 'skill-check.js');
  let exitCode = 0;
  try {
    execSync(`node "${cliPath}" validate "${dir}"`, { encoding: 'utf-8', stdio: 'pipe' });
  } catch (error) {
    exitCode = error.status;
  }
  assert(exitCode === 1, 'CLI validate exits 1 on invalid skill');
}

{
  const dir = createSkill('cli-props', '---\nname: cli-props\ndescription: Props test.\n---\n');
  const cliPath = path.resolve(__dirname, '..', 'tools', 'skill-check', 'skill-check.js');
  const result = execSync(`node "${cliPath}" read-properties "${dir}"`, { encoding: 'utf-8' });
  const json = JSON.parse(result);
  assert(json.name === 'cli-props', 'CLI read-properties returns correct name');
  assert(json.description === 'Props test.', 'CLI read-properties returns correct description');
}

{
  const dir = createSkill('cli-prompt', '---\nname: cli-prompt\ndescription: Prompt test.\n---\n');
  const cliPath = path.resolve(__dirname, '..', 'tools', 'skill-check', 'skill-check.js');
  const result = execSync(`node "${cliPath}" to-prompt "${dir}"`, { encoding: 'utf-8' });
  assert(result.includes('<available_skills>'), 'CLI to-prompt generates XML');
  assert(result.includes('cli-prompt'), 'CLI to-prompt includes skill name');
}

// ── Cleanup ──

fs.rmSync(tmpDir, { recursive: true, force: true });

// ── Results ──

